command:
# Step 1: Find all project folders with package.json (excluding node_modules)
$projects = Get-ChildItem -Path $env:USERPROFILE -Recurse -Filter 'package.json' -ErrorAction SilentlyContinue | Where-Object { $_.FullName -notmatch 'node_modules|antigravity|\.gemini' } | Select-Object -First 10 -ExpandProperty DirectoryName

Write-Output '=== PROJECT FOLDERS FOUND ==='
$projects | ForEach-Object { Write-Output $_ }

# Step 2: For each project, list dependencies and node_modules sizes
foreach ($proj in $projects) {
    Write-Output "`n=== PROJECT: $proj ==="
    $pkgFile = Join-Path $proj 'package.json'
    if (Test-Path $pkgFile) {
        $pkg = Get-Content $pkgFile -Raw | ConvertFrom-Json
        Write-Output '--- dependencies ---'
        if ($pkg.dependencies) { $pkg.dependencies.PSObject.Properties | ForEach-Object { Write-Output "  $($_.Name): $($_.Value)" } }
        Write-Output '--- devDependencies ---'
        if ($pkg.devDependencies) { $pkg.devDependencies.PSObject.Properties | ForEach-Object { Write-Output "  $($_.Name): $($_.Value)" } }
    }
    $nmPath = Join-Path $proj 'node_modules'
    if (Test-Path $nmPath) {
        Write-Output '--- node_modules top-level sizes (MB) ---'
        Get-ChildItem -Path $nmPath -Directory | ForEach-Object {
            $size = (Get-ChildItem -Path $_.FullName -Recurse -File -ErrorAction SilentlyContinue | Measure-Object -Property Length -Sum).Sum / 1MB
            Write-Output "  $($_.Name): $([math]::Round($size, 2)) MB"
        } | Sort-Object -Descending
    }
}
